"use client";

import * as CheckboxPrimitive from "@radix-ui/react-checkbox";
import { cn, tv, type VariantProps } from "@tendtoyj/cds-core";
import { Check, Minus } from "@tendtoyj/cds-icons/icons";
import * as React from "react";

const checkbox = tv({
  slots: {
    root: [
      "peer inline-flex shrink-0 items-center justify-center",
      "rounded-[4px] border",
      "border-[var(--cds-line-normal-neutral)]",
      "bg-[var(--cds-background-elevated-normal)]",
      "text-[color:var(--cds-inverse-label)]",
      "transition-[background-color,border-color,color]",
      "duration-[var(--cds-duration-fast)]",
      "focus-visible:outline-none focus-visible:ring-2",
      "focus-visible:ring-[color:var(--cds-focus-ring)] focus-visible:ring-offset-2",
      "focus-visible:ring-offset-[color:var(--cds-background-normal-normal)]",
      "data-[state=checked]:bg-[var(--cds-primary-normal)]",
      "data-[state=checked]:border-[var(--cds-primary-normal)]",
      "data-[state=indeterminate]:bg-[var(--cds-primary-normal)]",
      "data-[state=indeterminate]:border-[var(--cds-primary-normal)]",
      "disabled:cursor-default disabled:pointer-events-none",
      "disabled:bg-[var(--cds-interaction-disable)]",
      "disabled:border-[var(--cds-line-normal-alternative)]",
      "aria-invalid:border-[var(--cds-status-negative)]",
    ],
    indicator: ["flex items-center justify-center", "text-[color:var(--cds-inverse-label)]"],
  },
  variants: {
    size: {
      sm: {
        root: "w-[var(--cds-toggle-size-sm)] h-[var(--cds-toggle-size-sm)]",
        indicator: "[&_svg]:w-[var(--cds-toggle-icon-sm)] [&_svg]:h-[var(--cds-toggle-icon-sm)]",
      },
      md: {
        root: "w-[var(--cds-toggle-size-md)] h-[var(--cds-toggle-size-md)]",
        indicator: "[&_svg]:w-[var(--cds-toggle-icon-md)] [&_svg]:h-[var(--cds-toggle-icon-md)]",
      },
    },
  },
  defaultVariants: {
    size: "md",
  },
});

type CheckboxVariants = VariantProps<typeof checkbox>;

type CheckboxProps = Omit<
  React.ComponentPropsWithoutRef<typeof CheckboxPrimitive.Root>,
  "checked" | "defaultChecked"
> & {
  size?: CheckboxVariants["size"];
  invalid?: boolean;
  indeterminate?: boolean;
  checked?: boolean;
  defaultChecked?: boolean;
};

const Checkbox = React.forwardRef<React.ElementRef<typeof CheckboxPrimitive.Root>, CheckboxProps>(
  function Checkbox(
    {
      className,
      size = "md",
      invalid = false,
      indeterminate = false,
      checked,
      defaultChecked,
      ...props
    },
    ref,
  ) {
    const styles = checkbox({ size });
    const resolvedChecked: CheckboxPrimitive.CheckedState | undefined = indeterminate
      ? "indeterminate"
      : checked;
    const resolvedDefault: CheckboxPrimitive.CheckedState | undefined = indeterminate
      ? "indeterminate"
      : defaultChecked;

    return (
      <CheckboxPrimitive.Root
        ref={ref}
        checked={resolvedChecked}
        defaultChecked={resolvedDefault}
        aria-invalid={invalid || undefined}
        className={cn(styles.root(), className)}
        {...props}
      >
        <CheckboxPrimitive.Indicator className={styles.indicator()}>
          {indeterminate ? <Minus weight="bold" /> : <Check weight="bold" />}
        </CheckboxPrimitive.Indicator>
      </CheckboxPrimitive.Root>
    );
  },
);

export type { CheckboxProps };
export { Checkbox, checkbox };
